/** User-facing message when the server returns HTML (e.g. Vercel deployment protection) instead of JSON. */
export function isLikelyHtmlGatewayBody(data) {
  if (typeof data !== "string") return false;
  const s = data.slice(0, 400).toLowerCase();
  return (
    s.includes("<!doctype") ||
    s.includes("authentication required") ||
    s.includes("vercel authentication") ||
    s.includes("vercel-user-meta")
  );
}

export function apiUnreachableMessage() {
  return "Impossible de joindre l’API : URL incorrecte ou accès bloqué (ex. protection Vercel). Définissez REACT_APP_API_BASE_URL dans .env (ex. http://localhost:5000 en local), démarrez le backend, ou désactivez la protection sur le déploiement backend.";
}
